mapper.select:
select st.id, st.source_type, st.school_name, st.college_name, st.program_code, st.program_name, st.year, st.score_line, st.single_politics, st.single_english, st.single_math, st.single_professional, st.confidence, st.status, st.source_url, st.created_at, st.updated_at, st.reviewed_at, st.review_note, st.matched_program_id, concat(coalesce(s.name,''), ' / ', coalesce(c.name,''), ' / ', coalesce(p.program_code,''), ' ', coalesce(p.program_name,'')) matched_program_label from staging st left join program p on p.id = st.matched_program_id left join college c on c.id = p.college_id left join school s on s.id = c.school_id
and st.school_name like concat('%', #{schoolName}, '%')
and st.program_code = #{programCode}
and st.year = #{year}
and st.status = #{status}
and st.confidence = #{confidence}
and st.source_type = #{sourceType}
and st.matched_program_id is not null
and st.matched_program_id is null
and st.exam_subjects like '%408%'
order by st.created_at desc

